"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[57326],{75267(e,t,s){s.r(t),s.d(t,{assets:()=>c,contentTitle:()=>n,default:()=>l,frontMatter:()=>r,metadata:()=>o,toc:()=>h});let o=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets/customer-s-right-to-receive-access-t-164bbd17bd","title":"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)","description":"March 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets/Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IAS 38 Intangible Assets","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"customer-s-right-to-receive-access-t-164bbd17bd","title":"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Negative Low Emission Vehicle Credits (IAS 37)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-37-provisions-contingent-liabili-b0bcdf04e8/negative-low-emission-vehicle-credit-859bc1a3fd"},"next":{"title":"Player Transfer Payments (IAS 38)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/player-transfer-payments-ias-38-7cb77accfb"}}');var a=s(74848),i=s(28453);let r={id:"customer-s-right-to-receive-access-t-164bbd17bd",title:"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ias-38-intangible-assets-ac4723e282/customer-s-right-to-receive-access-t-164bbd17bd",sidebar_position:1},n="Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)",c={},h=[{value:"Does the customer receive a software asset at the contract commencement date or a service over the contract term?",id:"does-the-customer-receive-a-software-asset-at-the-contract-commencement-date-or-a-service-over-the-contract-term",level:2},{value:"A software lease",id:"a-software-lease",level:2},{value:"A software intangible asset",id:"a-software-intangible-asset",level:2}];function d(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"customers-right-to-receive-access-to-the-suppliers-software-hosted-on-the-cloud-ias-38",children:"Customer\u2019s Right to Receive Access to the Supplier\u2019s Software Hosted on the Cloud (IAS 38)"})}),"\n",(0,a.jsx)(t.p,{children:"March 2019"}),"\n",(0,a.jsx)(t.p,{children:"The Committee received a request about how a customer accounts for a \u2018Software as a Service\u2019 cloud computing arrangement in which the customer contracts to pay a fee in exchange for a right to receive access to the supplier\u2019s application software for a specified term. The supplier\u2019s software runs on cloud infrastructure managed and controlled by the supplier. The customer accesses the software on an as needed basis over the internet or via a dedicated line. The contract does not convey to the customer any rights over tangible assets."}),"\n",(0,a.jsx)(t.h2,{id:"does-the-customer-receive-a-software-asset-at-the-contract-commencement-date-or-a-service-over-the-contract-term",children:"Does the customer receive a software asset at the contract commencement date or a service over the contract term?"}),"\n",(0,a.jsx)(t.p,{children:"The Committee noted that a customer receives a software asset at the contract commencement date if either (a) the contract contains a software lease, or (b) the customer otherwise obtains control of software at the contract commencement date."}),"\n",(0,a.jsx)(t.h2,{id:"a-software-lease",children:"A software lease"}),"\n",(0,a.jsx)(t.p,{children:"IFRS 16 Leases defines a lease as \u2018a contract, or part of a contract, that conveys the right to use an asset (the underlying asset) for a period of time in exchange for consideration\u2019. Paragraphs 9 and B9 of IFRS 16 explain that a contract conveys the right to use an asset if, throughout the period of use, the customer has both:"}),"\n",(0,a.jsx)(t.p,{children:"a. the right to obtain substantially all the economic benefits from use of the asset (an identified asset); and\nb. the right to direct the use of that asset."}),"\n",(0,a.jsx)(t.p,{children:"Paragraphs B9\u2013B31 of IFRS 16 provide application guidance on the definition of a lease. Among other requirements, that application guidance specifies that a customer generally has the right to direct the use of an asset by having decision-making rights to change how and for what purpose the asset is used throughout the period of use. Accordingly, in a contract that contains a lease the supplier has given up those decision-making rights and transferred them to the customer at the lease commencement date."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that a right to receive future access to the supplier\u2019s software running on the supplier\u2019s cloud infrastructure does not in itself give the customer any decision-making rights about how and for what purpose the software is used\u2014the supplier would have those rights by, for example, deciding how and when to update or reconfigure the software, or deciding on which hardware (or infrastructure) the software will run. Accordingly, if a contract conveys to the customer only the right to receive access to the supplier\u2019s application software over the contract term, the contract does not contain a software lease."}),"\n",(0,a.jsx)(t.h2,{id:"a-software-intangible-asset",children:"A software intangible asset"}),"\n",(0,a.jsx)(t.p,{children:"IAS 38 defines an intangible asset as \u2018an identifiable non-monetary asset without physical substance\u2019. It notes that an asset is a resource controlled by the entity and paragraph 13 specifies that an entity controls an intangible asset if it has the power to obtain the future economic benefits flowing from the underlying resource and to restrict the access of others to those benefits."}),"\n",(0,a.jsx)(t.p,{children:"The Committee observed that, if a contract conveys to the customer only the right to receive access to the supplier\u2019s application software over the contract term, the customer does not receive a software intangible asset at the contract commencement date. A right to receive future access to the supplier\u2019s software does not, at the contract commencement date, give the customer the power to obtain the future economic benefits flowing from the software itself and to restrict others\u2019 access to those benefits."}),"\n",(0,a.jsx)(t.p,{children:"Consequently, the Committee concluded that a contract that conveys to the customer only the right to receive access to the supplier\u2019s application software in the future is a service contract. The customer receives the service\u2014the access to the software\u2014over the contract term. If the customer pays the supplier before it receives the service, that prepayment gives the customer a right to future service and is an asset for the customer."}),"\n",(0,a.jsx)(t.p,{children:"The Committee concluded that the requirements in IFRS Standards provide an adequate basis for an entity to account for fees paid or payable to receive access to the supplier\u2019s application software in Software as a Service arrangements. Consequently, the Committee decided not to add this matter to its standard-setting agenda."})]})}function l(e={}){let{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,s){s.d(t,{R:()=>r,x:()=>n});var o=s(96540);let a={},i=o.createContext(a);function r(e){let t=o.useContext(i);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function n(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);